from pathlib import Path
OPS = [
    ("w", ".github/workflows/automaton-3.yml", "name: AEGIS Automaton-3\n\non:\n  pull_request:\n    branches: [main]\n  merge_group:\n    branches: [main]\n  push:\n    branches: [main]\n\npermissions:\n  contents: read\n  id-token: write\n  attestations: write\n  artifact-metadata: write\n\njobs:\n  automaton-3:\n    name: aegis / automaton-3\n    runs-on: ubuntu-latest\n    timeout-minutes: 20\n    env:\n      CANDIDATE_SHA: ${{ github.event.pull_request.head.sha || github.event.merge_group.head_sha || github.sha }}\n      EXPECTED_PARENT_SHA: ${{ github.event.pull_request.base.sha || github.event.merge_group.base_sha || github.event.before }}\n    steps:\n      - name: Checkout exact candidate\n        uses: actions/checkout@v4\n        with:\n          ref: ${{ env.CANDIDATE_SHA }}\n          fetch-depth: 0\n\n      - name: Resolve deterministic parent\n        shell: bash\n        run: |\n          set -euo pipefail\n          if [[ -z \"$EXPECTED_PARENT_SHA\" || \"$EXPECTED_PARENT_SHA\" =~ ^0+$ ]]; then\n            echo \"EXPECTED_PARENT_SHA=$(git rev-parse \"${CANDIDATE_SHA}^\")\" >> \"$GITHUB_ENV\"\n          fi\n\n      - name: Set up Python\n        uses: actions/setup-python@v5\n        with:\n          python-version: '3.12'\n\n      - name: Set up Node\n        uses: actions/setup-node@v4\n        with:\n          node-version: '20'\n          cache: npm\n          cache-dependency-path: sovereign-omega-v2/mcp-server/package-lock.json\n\n      - name: Install exact schema validator\n        run: pip install jsonschema==4.23.0\n\n      - name: Validate JSON schemas\n        shell: bash\n        run: |\n          set -euo pipefail\n          python - <<'PY'\n          import json\n          from pathlib import Path\n          from jsonschema.validators import validator_for\n          for path in sorted(Path('schemas').glob('*-envelope.v1.schema.json')) + sorted(Path('schemas').glob('*-receipt.v1.schema.json')) + [Path('schemas/writer-lease.v1.schema.json')]:\n              schema = json.loads(path.read_text(encoding='utf-8'))\n              validator_for(schema).check_schema(schema)\n              print(f'SCHEMA_OK {path}')\n          PY\n\n      - name: Run authority-abuse matrix at k=1,10,100\n        run: |\n          python scripts/run-automaton3-tests.py \\\n            --output \"$RUNNER_TEMP/AUTOMATON3_TEST_SUMMARY.json\" \\\n            --log \"$RUNNER_TEMP/AUTOMATON3_TEST.log\"\n\n      - name: Build and test MCP fail-closed integration\n        working-directory: sovereign-omega-v2/mcp-server\n        shell: bash\n        run: |\n          set -euo pipefail\n          npm ci\n          npm run test:resources\n          npm run test:automaton3 | tee \"$RUNNER_TEMP/AUTOMATON3_MCP.log\"\n\n      - name: Validate claims and constitutional anchors\n        shell: bash\n        run: |\n          set -euo pipefail\n          node scripts/validate-claims.mjs\n          (cd sovereign-omega-v2 && node scripts/verify-hashes.mjs)\n\n      - name: Verify repository control contracts\n        shell: bash\n        run: |\n          set -euo pipefail\n          test -f .github/workflows/automaton-2.yml\n          test -f .github/workflows/experiment-admission.yml\n          test -f .github/workflows/integration-ledger.yml\n          test -f .github/workflows/osv-scanner.yml\n          test -f .github/workflows/ci.yml\n          grep -F 'aegis / automaton-2' .github/workflows/automaton-2.yml\n          grep -F 'aegis / automaton-3' .github/workflows/automaton-3.yml\n          grep -F 'merge_group:' .github/workflows/automaton-2.yml\n          grep -F 'merge_group:' .github/workflows/automaton-3.yml\n\n      - name: Validate exact candidate and emit deterministic receipt\n        shell: bash\n        run: |\n          set -euo pipefail\n          python scripts/validate-automaton3.py \\\n            --candidate-sha \"$CANDIDATE_SHA\" \\\n            --expected-parent-sha \"$EXPECTED_PARENT_SHA\" \\\n            --test-summary \"$RUNNER_TEMP/AUTOMATON3_TEST_SUMMARY.json\" \\\n            --mcp-log \"$RUNNER_TEMP/AUTOMATON3_MCP.log\" \\\n            --receipt-output \"$RUNNER_TEMP/AUTOMATON3_RECEIPT.json\" \\\n            --manifest-output \"$RUNNER_TEMP/AUTOMATON3_CANDIDATE_MANIFEST.json\" \\\n            --require-oidc\n\n      - name: Build deterministic replay package\n        shell: bash\n        run: |\n          set -euo pipefail\n          replay=\"$RUNNER_TEMP/automaton3-replay\"\n          mkdir -p \"$replay\"\n          cp \"$RUNNER_TEMP/AUTOMATON3_RECEIPT.json\" \"$replay/\"\n          cp \"$RUNNER_TEMP/AUTOMATON3_CANDIDATE_MANIFEST.json\" \"$replay/\"\n          cp \"$RUNNER_TEMP/AUTOMATON3_TEST_SUMMARY.json\" \"$replay/\"\n          cp \"$RUNNER_TEMP/AUTOMATON3_TEST.log\" \"$replay/\"\n          cp \"$RUNNER_TEMP/AUTOMATON3_MCP.log\" \"$replay/\"\n          cp harness/policies/consequence-policy.v1.json \"$replay/\"\n          cp harness/policies/capability-map.v1.json \"$replay/\"\n          git diff --name-only \"$EXPECTED_PARENT_SHA...$CANDIDATE_SHA\" | LC_ALL=C sort > \"$replay/CHANGED_FILES.txt\"\n          plan=\".aegis/experiments/pr-221-automaton-3-sovereign-execution-v1.json\"\n          if [[ -f \"$plan\" ]]; then cp \"$plan\" \"$replay/EXPERIMENT_PLAN.json\"; fi\n          (\n            cd \"$replay\"\n            find . -maxdepth 1 -type f ! -name SHA256SUMS -printf '%f\\n' \\\n              | LC_ALL=C sort \\\n              | xargs sha256sum > SHA256SUMS\n          )\n\n      - name: Upload Automaton-3 replay evidence\n        uses: actions/upload-artifact@v4\n        with:\n          name: aegis-automaton-3-${{ env.CANDIDATE_SHA }}\n          path: ${{ runner.temp }}/automaton3-replay\n          if-no-files-found: error\n          retention-days: 90\n\n      - name: Attest exact Automaton-3 candidate\n        uses: actions/attest@v4\n        with:\n          subject-path: |\n            ${{ runner.temp }}/AUTOMATON3_RECEIPT.json\n            ${{ runner.temp }}/AUTOMATON3_CANDIDATE_MANIFEST.json\n            ${{ runner.temp }}/AUTOMATON3_TEST_SUMMARY.json\n            harness/policies/consequence-policy.v1.json\n            harness/policies/capability-map.v1.json\n            schemas/execution-identity-envelope.v1.schema.json\n            schemas/mutation-receipt.v1.schema.json\n"),
    ("w", "agents/coordinator.py", "\"\"\"Governed AEGIS coordinator boundary using the single Automaton-3 evaluator.\n\nThe historical implementation remains in :mod:`agents.coordinator_legacy`. This\nmodule re-exports its API, but no agent dispatch receives operational authority\nfrom documentation priors or local scoring. The final decision is made only by\n``harness.sdk.authority_client.authorize_from_environment``.\n\"\"\"\nfrom __future__ import annotations\n\nimport json\nimport os\nimport time\nfrom dataclasses import asdict, dataclass\nfrom pathlib import Path\nfrom typing import Any\n\nfrom agents import coordinator_legacy as _legacy\nfrom harness.sdk.authority_client import authorize_from_environment\nfrom harness.sdk.skill_routing import ADMITTED, DENIED, SkillRoutingReceipt, record_skill_observation\n\nfor _name in dir(_legacy):\n    if not _name.startswith(\"__\") and _name not in globals():\n        globals()[_name] = getattr(_legacy, _name)\n\nROLE_RECEIPT_KIND = \"AEGIS_COORDINATOR_ROLE_ROUTING_RECEIPT_V2\"\n\n\n@dataclass(frozen=True)\nclass RoleRoutingReceipt:\n    schema_version: str\n    receipt_kind: str\n    role: str\n    outcome: str\n    authority_score: float\n    capability_receipt_hashes: tuple[str, ...]\n    reason_codes: tuple[str, ...]\n    receipt_hash: str\n\n\nclass SkillRouter(_legacy.SkillRouter):\n    \"\"\"Compatibility facade; operational authority comes only from Automaton-3.\"\"\"\n\n    def __init__(self, *, skill_tree_path: str | Path = _legacy.SKILL_TREE_PATH, repo_root: str | Path = _legacy._REPO_ROOT, capability_map: dict[str, str] | None = None) -> None:\n        self._tree: dict[str, Any] | None = None\n        self._skill_tree_path = Path(skill_tree_path)\n        self._repo_root = Path(repo_root).resolve()\n        self._capability_map = dict(capability_map or _legacy.CAPABILITY_SKILL_MAP)\n        self._last_mutation_error: str | None = None\n\n    def _central_decision(self, *, role: str, task_instruction: str) -> dict[str, Any]:\n        action = {\"operation\": \"agent-dispatch\", \"role\": role, \"instruction_digest\": __import__(\"hashlib\").sha256(task_instruction.encode(\"utf-8\")).hexdigest()}\n        return authorize_from_environment(\n            action_class=\"D1\",\n            authority_domain=\"agent:dispatch\",\n            requested_capability=\"coordinator.dispatch\",\n            tool=\"agents.coordinator:dispatch\",\n            target=role,\n            action=action,\n        )\n\n    def competency_decision(self, skill_id: str, *, capability: str | None = None) -> SkillRoutingReceipt:\n        decision = self._central_decision(role=skill_id, task_instruction=capability or skill_id)\n        score = float(decision.get(\"authority_score\", \"0\")) if decision.get(\"outcome\") == ADMITTED else 0.0\n        body = {\n            \"schema_version\": \"2.0.0\", \"receipt_kind\": \"AEGIS_COORDINATOR_ROUTING_RECEIPT_V2\",\n            \"capability\": capability or skill_id, \"skill_id\": skill_id,\n            \"outcome\": decision.get(\"outcome\", DENIED), \"authority_score\": score,\n            \"observation_state\": \"CENTRAL_AUTHORITY\", \"validated_runs\": 0,\n            \"registry_root\": None, \"registry_receipt_hash\": None,\n            \"reason_codes\": tuple(decision.get(\"denial_codes\", [])),\n        }\n        return SkillRoutingReceipt(**body, receipt_hash=str(decision.get(\"decision_root\")))\n\n    def competency_score(self, skill_id: str) -> float:\n        return self.competency_decision(skill_id).authority_score\n\n    def capability_decision(self, capability: str) -> SkillRoutingReceipt:\n        return self.competency_decision(self._capability_map.get(capability, capability), capability=capability)\n\n    def capability_score(self, capability: str) -> float:\n        return self.capability_decision(capability).authority_score\n\n    def role_routing_receipt(self, role: \"AgentRole\", task_instruction: str, agent_defs: dict[str, Any]) -> RoleRoutingReceipt:\n        decision = self._central_decision(role=role.value, task_instruction=task_instruction)\n        outcome = decision.get(\"outcome\", DENIED)\n        score = float(decision.get(\"authority_score\", \"0\")) if outcome == ADMITTED else 0.0\n        reasons = tuple(sorted(set(decision.get(\"denial_codes\", []))))\n        root = str(decision.get(\"decision_root\"))\n        return RoleRoutingReceipt(\"2.0.0\", ROLE_RECEIPT_KIND, role.value, outcome, score, (root,), reasons, root)\n\n    def score_role_for_task(self, role: \"AgentRole\", task_instruction: str, agent_defs: dict[str, Any]) -> float:\n        return self.role_routing_receipt(role, task_instruction, agent_defs).authority_score\n\n    def emit_skill_event(self, capability: str, success: bool) -> None:\n        \"\"\"Record telemetry only; an observation never grants authority by itself.\"\"\"\n        skill_id = self._capability_map.get(capability)\n        try:\n            tree = json.loads(self._skill_tree_path.read_text(encoding=\"utf-8\"))\n            if skill_id is None:\n                raise ValueError(\"unmapped capability\")\n            observed_at = time.strftime(\"%Y-%m-%dT%H:%M:%S+00:00\", time.gmtime())\n            updated = record_skill_observation(tree, skill_id=skill_id, success=success, observed_at=observed_at, repo_root=self._repo_root)\n            temporary = self._skill_tree_path.with_suffix(\".json.tmp\")\n            temporary.write_text(json.dumps(updated, ensure_ascii=False, indent=2) + \"\\n\", encoding=\"utf-8\")\n            os.replace(temporary, self._skill_tree_path)\n            self._last_mutation_error = None\n        except (OSError, TypeError, ValueError) as exc:\n            self._last_mutation_error = type(exc).__name__\n\n\n_legacy.SkillRouter = SkillRouter\n_skill_router = SkillRouter()\n_legacy._skill_router = _skill_router\n_last_dispatch_receipts: tuple[RoleRoutingReceipt, ...] = ()\n\n\nasync def dispatch_event(event_type: str, payload: dict) -> list[\"AgentResult\"]:\n    global _last_dispatch_receipts\n    candidate_roles = _legacy.EVENT_ROUTING.get(event_type, [_legacy.AgentRole.ENGINEERING])\n    definitions = _legacy._load_agent_defs(); agent_defs = definitions.get(\"agents\", {})\n    instruction_sample = _legacy._event_to_instruction(event_type, payload, candidate_roles[0])\n    indexed = [(index, role, _skill_router.role_routing_receipt(role, instruction_sample, agent_defs)) for index, role in enumerate(candidate_roles)]\n    _last_dispatch_receipts = tuple(item[2] for item in indexed)\n    admitted = [item for item in indexed if item[2].outcome == ADMITTED]\n    admitted.sort(key=lambda item: (-item[2].authority_score, item[0]))\n    results: list[AgentResult] = []\n    for _, role, _receipt in admitted:\n        task = _legacy.AgentTask(task_id=str(_legacy.uuid.uuid4()), role=role, instruction=_legacy._event_to_instruction(event_type, payload, role), context={\"event_type\": event_type, \"payload\": payload}, max_ralph_cycles=3)\n        results.append(await _legacy.run_agent(task))\n    return results\n\n\ndef last_dispatch_receipts() -> tuple[dict[str, Any], ...]:\n    return tuple(asdict(receipt) for receipt in _last_dispatch_receipts)\n\n\n_legacy.dispatch_event = dispatch_event\n_legacy.last_dispatch_receipts = last_dispatch_receipts\n\n\ndef main() -> None:\n    _legacy.main()\n\n\nif __name__ == \"__main__\":\n    main()\n"),
    ("w", "docs/adr/ADR-0021-automaton-3-sovereign-execution.md", "# ADR-0021: Automaton-3 sovereign execution control plane\n\nStatus: Proposed for exact-head admission  \nCanonical base: `0e40ddf71090e6ff680c4eb7e721af98d4cea1d6`\n\n## Decision\n\nAll consequential execution uses one deterministic authority evaluator in `harness/sdk/sovereign_execution.py`. Entry points may adapt transport and evidence formats, but they may not implement an independent authority score or bypass the evaluator.\n\nThe control plane separates five concerns:\n\n1. `ExecutionIdentityEnvelope` binds the request to canonical repository identity, source commit, logical repository root, actor, physical executor, workflow, capability, policy, registry, and action digests.\n2. `WorkspaceBinding` binds the canonical remote, logical root, project identity, source commit, and operator authorization. Absolute paths remain observational metadata.\n3. `AuthorityEvaluator` applies the D0–D4 consequence policy and evidence-bound capability registry. Unknown, unobserved, under-validated, unavailable, or unmapped capabilities receive zero operational authority.\n4. `WriterLeaseManager` provides one active writer per authority domain, monotone generations, fencing tokens, expected-parent checks, and replay rejection.\n5. `DurableExecutionRegistry`, `EventEnvelope`, and `ReceiptChain` preserve operator visibility, mediated communication, idempotency, cancellation, and deterministic mutation or denial evidence.\n\n## Determinism boundary\n\nDeterministic roots contain no wall-clock timestamp, random ordering, host-specific absolute path, mutable deployment label, or unredacted secret. Operational time and resolved paths are attached as observational metadata and are not hashed into identity, policy, lease, event, or mutation roots.\n\n## Workspace root convention\n\nThe deterministic `repository_root` and `workspace_root` are the logical root `.`. The exact resolved host path is recorded in `WorkspaceObservation`. This prevents two runners in different absolute directories from producing different identity roots while still exposing the physical execution location to the operator.\n\n## Integration\n\n- `agents/coordinator.py` grants dispatch authority only through `authorize_from_environment`.\n- MCP consequential tools invoke `scripts/automaton3-authority.py`; an unavailable evaluator or identity denies before bridge access.\n- CI invokes the same core module for policy, workspace, lease, durable execution, event, and receipt tests.\n- D0 read-only MCP resources remain key-free and cannot mutate state.\n\n## External-runtime boundary\n\nThis PR implements a deterministic local reference model and interfaces for durable execution. It does not claim that Temporal, LangGraph, Kubernetes, or any cloud worker runtime is deployed.\n"),
]
for mode, path, content in OPS:
    target = Path(path)
    target.parent.mkdir(parents=True, exist_ok=True)
    with target.open('w' if mode == 'w' else 'a', encoding='utf-8', newline='') as handle:
        handle.write(content)
